package ru.kryuch.krtg.searcher.service;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.springframework.stereotype.Service;import ru.kryuch.krtg.searcher.config.TelegramSettingsResolver;import ru.kryuch.krtg.searcher.dto.ChatInfo;import ru.kryuch.krtg.searcher.dto.MessagesHistory;import ru.kryuch.krtg.searcher.dto.SearchParams;import ru.kryuch.krtg.searcher.integration.dto.ChatIdsRequest;import ru.kryuch.krtg.searcher.integration.dto.SendBulkMessageRequestByConcatUsername;import ru.kryuch.krtg.searcher.integration.dto.SendBulkMessageRequestByContactId;import ru.kryuch.krtg.searcher.integration.tg.TelegramPythonClient;import ru.kryuch.krtg.searcher.mapper.ChatMapper;import ru.kryuch.krtg.searcher.util.PythonMessagesResponse;import ru.kryuch.krtg.searcher.util.SendResponse;import java.util.List;import java.util.Objects;import java.util.Set;@Slf4j@Service@RequiredArgsConstructorpublic class TelegramMessagingGateway {    private final TelegramPythonClient telegramClient;    private final TelegramSettingsResolver settings;    private final ChatMapper chatMapper;    public List<ChatInfo> sendMessage(String message,                                      Set<String> contactUsernames,                                      boolean onlyNew) {        log.info(                "Sending telegram message to {} chats",                contactUsernames        );        if (contactUsernames == null || contactUsernames.isEmpty()) {            return List.of();        }        SendResponse response =                telegramClient.sendBulkMessages(                        SendBulkMessageRequestByConcatUsername.builder()                                .contactUsernames(contactUsernames)                                .messageText(message)                                .delaySeconds(settings.getSendDelay())                                .onlyNewChats(onlyNew)                                .build()                );        return response.getResults().stream()                .map(chatMapper::fromSendResult)                .filter(Objects::nonNull)                .toList();    }    public List<ChatInfo> sendMessage(String message, Set<Long> contactIds) {        log.info("Sending telegram message to {} chats", contactIds);        if (contactIds == null || contactIds.isEmpty()) {            return List.of();        }        SendResponse response =                telegramClient.sendBulkMessages(                        SendBulkMessageRequestByContactId.builder()                                .contactIds(contactIds)                                .messageText(message)                                .delaySeconds(settings.getSendDelay())                                .build()                );        return response.getResults().stream()                .map(chatMapper::fromSendResult)                .filter(Objects::nonNull)                .toList();    }    public MessagesHistory getMessages(Long chatId, Integer limit) {        log.debug(                "Loading telegram history chatId={}, limit={}",                chatId,                limit        );        PythonMessagesResponse response =                telegramClient.getChatPreview(chatId, limit);        if (response == null || response.getMessages() == null) {            return new MessagesHistory();        }        MessagesHistory history = new MessagesHistory();        for (var msg : response.getMessages()) {            history.add(msg);        }        return history;    }    public List<ChatInfo> findAllChats() {        return telegramClient.findAllChats();    }    public List<ChatInfo> findChatsByIds(ChatIdsRequest request) {        return telegramClient.findChatsByIds(request);    }    public List<ChatInfo> searchChats(SearchParams params) {        return telegramClient.searchChats(params);    }}